import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  Container,
  Card,
  Row,
  Col,
  Spinner,
  Alert,
  Button,
  Badge,
} from "react-bootstrap";
import { getOrderDetail, cancelOrder } from "../services/orderService";
import { payOrder } from "../services/paymentService";import { getStoredUser } from "../services/authService";

function PaymentPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();

  const [order, setOrder] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  const [paying, setPaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(null);
  const [expiredHandled, setExpiredHandled] = useState(false);

  useEffect(() => {
    const fetchOrderDetail = async () => {
      try {
        setLoading(true);
        setError("");

        if (!orderId) {
          setError("Mã đơn hàng không hợp lệ.");
          return;
        }

        const response = await getOrderDetail(orderId);

        if (response.data?.success && response.data?.data) {
          setOrder(response.data.data);
        } else {
          setError("Không lấy được chi tiết đơn hàng.");
        }
      } catch (err) {
        console.error("Lỗi lấy chi tiết đơn hàng:", err);
        setError(
          err?.response?.data?.message || "Lỗi khi tải chi tiết đơn hàng."
        );
      } finally {
        setLoading(false);
      }
    };

    fetchOrderDetail();
  }, [orderId]);

  useEffect(() => {
    if (!order?.expires_at) return;

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const expireTime = new Date(order.expires_at).getTime();
      const diff = expireTime - now;

      if (diff <= 0) {
        setTimeLeft(0);
        clearInterval(interval);
      } else {
        setTimeLeft(diff);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [order]);

  useEffect(() => {
    const handleExpiredOrder = async () => {
      if (
        timeLeft === 0 &&
        order &&
        order.order_status === "awaiting_payment" &&
        order.payment_status !== "paid" &&
        !expiredHandled
      ) {
        try {
          setExpiredHandled(true);
          await cancelOrder(order.id);

          setOrder((prev) =>
            prev
              ? {
                  ...prev,
                  order_status: "expired",
                  payment_status: "expired",
                }
              : prev
          );

          setTimeout(() => {
            alert("Đơn hàng đã hết hạn.");
            navigate("/home");
          }, 1500);
        } catch (err) {
          console.error("Lỗi tự hủy đơn hết hạn:", err);

          setOrder((prev) =>
            prev
              ? {
                  ...prev,
                  order_status: "expired",
                  payment_status: "expired",
                }
              : prev
          );

          setTimeout(() => {
            alert("Đơn hàng đã hết hạn.");
            navigate("/home");
          }, 1500);
        }
      }
    };

    handleExpiredOrder();
  }, [timeLeft, order, expiredHandled, navigate]);

  const formatTime = (ms) => {
    const totalSeconds = Math.floor(ms / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes}:${seconds < 10 ? "0" : ""}${seconds}`;
  };

  const handleDemoPayment = async () => {
    try {
      if (!order) {
        alert("Không có thông tin đơn hàng.");
        return;
      }

      if (timeLeft === 0) {
        alert("Đơn hàng đã hết hạn thanh toán.");
        return;
      }

      const user = getStoredUser();

      setPaying(true);

      const payload = {
        order_id: Number(order.id),
        payment_method: "demo",
        amount: Number(order.total_amount),
        currency: "VND",
        gateway_transaction_id: `demo_txn_${Date.now()}`,
        gateway_response: {
          source: "frontend_demo",
          user_email: user?.email || null,
        },
      };

      const response = await processPayment(payload);

      if (response.data?.success) {
        alert("Thanh toán thành công.");
        navigate("/home");
      } else {
        alert(response.data?.message || "Thanh toán thất bại.");
      }
    } catch (err) {
      console.error("Lỗi thanh toán:", err);
      alert(
        err?.response?.data?.message || err?.message || "Lỗi khi thanh toán."
      );
    } finally {
      setPaying(false);
    }
  };

  const renderPaymentStatus = (status) => {
    switch (status) {
      case "paid":
        return <Badge bg="success">Đã thanh toán</Badge>;
      case "pending":
        return (
          <Badge bg="warning" text="dark">
            Chờ thanh toán
          </Badge>
        );
      case "expired":
        return <Badge bg="secondary">Hết hạn</Badge>;
      case "failed":
        return <Badge bg="danger">Thất bại</Badge>;
      case "refunded":
        return <Badge bg="info">Đã hoàn tiền</Badge>;
      default:
        return <Badge bg="dark">{status}</Badge>;
    }
  };

  const renderOrderStatus = (status) => {
    switch (status) {
      case "awaiting_payment":
        return (
          <Badge bg="warning" text="dark">
            Chờ thanh toán
          </Badge>
        );
      case "processing":
        return <Badge bg="info">Đang xử lý</Badge>;
      case "completed":
        return <Badge bg="success">Hoàn tất</Badge>;
      case "cancelled":
        return <Badge bg="secondary">Đã hủy</Badge>;
      case "expired":
        return <Badge bg="dark">Hết hạn</Badge>;
      default:
        return <Badge bg="primary">{status}</Badge>;
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "100vh" }}
      >
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  if (error) {
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  if (!order) {
    return (
      <Container className="my-5">
        <Alert variant="warning">Không tìm thấy đơn hàng.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row className="mb-4">
        <Col>
          <h2>Thanh toán đơn hàng</h2>
          <p className="text-muted mb-0">Mã đơn hàng: #{order.id}</p>
        </Col>
      </Row>

      <Row className="g-4">
        <Col lg={8}>
          <Card className="shadow-sm">
            <Card.Body>
              <h4 className="mb-3">Chi tiết đơn hàng</h4>

              <p>
                <strong>Trạng thái đơn:</strong> {renderOrderStatus(order.order_status)}
              </p>

              <p>
                <strong>Trạng thái thanh toán:</strong>{" "}
                {renderPaymentStatus(order.payment_status)}
              </p>

              <p>
                <strong>Tổng tiền:</strong>{" "}
                {Number(order.total_amount || 0).toLocaleString("vi-VN")} VNĐ
              </p>

              {order.expires_at && (
                <>
                  <p>
                    <strong>Hết hạn lúc:</strong>{" "}
                    {new Date(order.expires_at).toLocaleString("vi-VN")}
                  </p>

                  <p>
                    <strong>Thời gian còn lại:</strong>{" "}
                    {timeLeft !== null ? (
                      timeLeft > 0 ? (
                        <span style={{ color: "red", fontWeight: "bold" }}>
                          {formatTime(timeLeft)}
                        </span>
                      ) : (
                        <span style={{ color: "gray", fontWeight: "bold" }}>
                          Đã hết hạn
                        </span>
                      )
                    ) : (
                      "Đang tính..."
                    )}
                  </p>
                </>
              )}

              <hr />

              <h5 className="mb-3">Danh sách vé</h5>

              {Array.isArray(order.items) && order.items.length > 0 ? (
                order.items.map((item) => (
                  <Card key={item.id} className="mb-3 border">
                    <Card.Body>
                      <p className="mb-2">
                        <strong>Loại vé:</strong>{" "}
                        {item.ticket_type_name_snapshot ||
                          item.ticket_type_name ||
                          "Không rõ"}
                      </p>

                      <p className="mb-2">
                        <strong>Số lượng:</strong> {item.quantity}
                      </p>

                      <p className="mb-2">
                        <strong>Đơn giá:</strong>{" "}
                        {Number(item.unit_price || 0).toLocaleString("vi-VN")} VNĐ
                      </p>

                      <p className="mb-0">
                        <strong>Thành tiền:</strong>{" "}
                        {Number(item.subtotal || 0).toLocaleString("vi-VN")} VNĐ
                      </p>
                    </Card.Body>
                  </Card>
                ))
              ) : (
                <Alert variant="warning" className="mb-0">
                  Không có item trong đơn hàng.
                </Alert>
              )}
            </Card.Body>
          </Card>
        </Col>

        <Col lg={4}>
          <Card className="shadow-sm">
            <Card.Body>
              <h4 className="mb-3">Phương thức thanh toán</h4>

              <p className="text-muted">
                Hiện tại dùng nút thanh toán demo để test luồng frontend ↔ backend.
              </p>

              <div className="d-grid gap-2">
                <Button
                  variant="success"
                  onClick={handleDemoPayment}
                  disabled={
                    paying ||
                    order.payment_status === "paid" ||
                    timeLeft === 0
                  }
                >
                  {timeLeft === 0
                    ? "Đơn đã hết hạn"
                    : paying
                    ? "Đang thanh toán..."
                    : order.payment_status === "paid"
                    ? "Đơn đã thanh toán"
                    : "Thanh toán demo"}
                </Button>

                <Button
                  variant="outline-secondary"
                  onClick={() => navigate("/home")}
                >
                  Quay về trang chủ
                </Button>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default PaymentPage;
